mapper.select:
SELECT place_id
FROM place
WHERE place_name = #{placeName}
  AND address    = #{address}
  AND ROWNUM = 1

SELECT placeId, placeName, address, latitude, longitude, category, imageUrl, phoneNumber, description FROM ( SELECT t.*, ROWNUM AS rn FROM ( SELECT p.place_id AS placeId, p.place_name AS placeName, p.address AS address, p.latitude AS latitude, p.longitude AS longitude, p.category AS category, p.image_url AS imageUrl, p.phone_number AS phoneNumber, p.description AS description FROM place p WHERE p.latitude IS NOT NULL AND p.longitude IS NOT NULL
AND (
p.address LIKE '%' || #{city} || '%'
)
AND p.category = #{category}
ORDER BY CASE WHEN p.image_url IS NOT NULL AND p.image_url != '' THEN 0 ELSE 1 END, DBMS_RANDOM.VALUE ) t WHERE ROWNUM <= (#{offset} + #{limit}) ) WHERE rn > #{offset}

SELECT COUNT(*) FROM place p WHERE p.latitude IS NOT NULL AND p.longitude IS NOT NULL
AND (
p.address LIKE '%' || #{city} || '%'
)
AND p.category = #{category}

mapper.update:
UPDATE place
SET phone_number = #{phoneNumber},
    description  = #{description}
WHERE place_id = #{placeId}

UPDATE place
SET image_url = #{imageUrl}
WHERE place_id = #{placeId}
  AND image_url IS NULL

UPDATE place
SET view_count = NVL(view_count, 0) + 1
WHERE place_id = #{placeId}

mapper.delete:
